/* ---------------- Exam generation ---------------- */
function generateExam(subjectId, levelId, seen = { q: [], c: [] }) {
  const cfg = LEVELS.find((l) => l.id === levelId);
  const seenQ = new Set(seen.q || []);
  const seenC = new Set(seen.c || []);

  const pool = QUESTIONS.filter((q) => q.subjectId === subjectId && q.level <= cfg.maxLevel);
  const byChapter = {};
  pool.forEach((q) => {
    byChapter[q.chapterId] = byChapter[q.chapterId] || [];
    byChapter[q.chapterId].push(q);
  });
  // au sein de chaque chapitre : questions jamais vues récemment en premier, puis les déjà vues
  Object.keys(byChapter).forEach((k) => {
    const unseen = shuffle(byChapter[k].filter((q) => !seenQ.has(q.id)));
    const already = shuffle(byChapter[k].filter((q) => seenQ.has(q.id)));
    byChapter[k] = [...unseen, ...already];
  });
  const chapterOrder = shuffle(Object.keys(byChapter));

  const picked = [];
  let round = 0;
  while (picked.length < cfg.numSingle) {
    let addedThisRound = false;
    for (const chId of chapterOrder) {
      if (picked.length >= cfg.numSingle) break;
      const arr = byChapter[chId];
      if (arr && arr[round]) {
        picked.push(arr[round]);
        addedThisRound = true;
      }
    }
    round++;
    if (!addedThisRound) break;
  }

  const casePoolAll = CASES.filter((c) => c.subjectId === subjectId && c.level <= cfg.maxLevel);
  const unseenCases = shuffle(casePoolAll.filter((c) => !seenC.has(c.id)));
  const alreadyCases = shuffle(casePoolAll.filter((c) => seenC.has(c.id)));
  const casePool = [...unseenCases, ...alreadyCases];
  const pickedCases = casePool.slice(0, cfg.numCases);

  // randomize option order per question, preserving correctness
  const randomizeOptions = (q) => ({ ...q, options: shuffle(q.options) });

  const singleItems = shuffle(picked).map((q) => ({ kind: "single", ...randomizeOptions(q) }));
  const caseItems = pickedCases.map((c) => ({
    kind: "case",
    id: c.id,
    chapterLabel: c.chapterLabel,
    vignette: c.vignette,
    reference: c.reference,
    questions: c.questions.map(randomizeOptions),
  }));

  // interleave: place cases after roughly 1/3 and 2/3 of singles
  const items = [];
  const segments = caseItems.length + 1;
  const chunk = Math.ceil(singleItems.length / segments);
  let idx = 0;
  caseItems.forEach((c) => {
    items.push(...singleItems.slice(idx, idx + chunk));
    idx += chunk;
    items.push(c);
  });
  items.push(...singleItems.slice(idx));

  return {
    subjectId, levelId, items, generatedAt: new Date().toISOString(),
    usedQIds: picked.map((q) => q.id),
    usedCIds: pickedCases.map((c) => c.id),
  };
}

// combine newly-used ids into the persisted "seen" record; once every item of a
// pool has been shown at least once, start a fresh cycle instead of getting stuck
function updateSeen(seen, exam) {
  const mergedQ = Array.from(new Set([...(seen.q || []), ...exam.usedQIds]));
  const mergedC = Array.from(new Set([...(seen.c || []), ...exam.usedCIds]));
  const subjectQTotal = QUESTIONS.filter((q) => q.subjectId === exam.subjectId).length;
  const subjectCTotal = CASES.filter((c) => c.subjectId === exam.subjectId).length;
  const nextQ = mergedQ.length >= subjectQTotal ? exam.usedQIds : mergedQ;
  const nextC = mergedC.length >= subjectCTotal ? exam.usedCIds : mergedC;
  return { q: nextQ, c: nextC };
}

// mode entraînement : pas de limite de temps, feedback immédiat après chaque
// réponse. On peut réviser un chapitre précis ou l'ensemble du cours.
function generateTraining(subjectId, chapterId) {
  const qPool = QUESTIONS.filter((q) => q.subjectId === subjectId && (chapterId === "all" || q.chapterId === chapterId));
  const cPool = CASES.filter((c) => c.subjectId === subjectId && (chapterId === "all" || c.chapterId === chapterId));
  const randomizeOptions = (q) => ({ ...q, options: shuffle(q.options) });

  const singleItems = shuffle(qPool).map((q) => ({ kind: "single", ...randomizeOptions(q) }));
  const caseItems = shuffle(cPool).map((c) => ({
    kind: "case",
    id: c.id,
    chapterLabel: c.chapterLabel,
    vignette: c.vignette,
    reference: c.reference,
    questions: c.questions.map(randomizeOptions),
  }));

  return { subjectId, chapterId, items: shuffle([...singleItems, ...caseItems]) };
}

function flattenGradable(items) {
  const flat = [];
  items.forEach((it) => {
    if (it.kind === "single") flat.push(it);
    else it.questions.forEach((q) => flat.push({ kind: "caseq", caseId: it.id, caseVignette: it.vignette, ...q }));
  });
  return flat;
}

/* ---------------- Scoring ---------------- */
function scoreExam(items, answers) {
  const flat = flattenGradable(items);
  let obtained = 0;
  let maxTotal = 0;
  let bonnes = 0, mauvaises = 0, oubliees = 0;
  const chapterStats = {};
  const details = flat.map((q) => {
    const sel = answers[q.id] || [];
    const correctIds = q.options.filter((o) => o.correct).map((o) => o.id);
    let pts, max;
    if (q.type === "QCU") {
      max = 1;
      pts = sel.length === 1 && correctIds.includes(sel[0]) ? 1 : 0;
    } else {
      max = correctIds.length;
      const rightPicked = sel.filter((s) => correctIds.includes(s)).length;
      const wrongPicked = sel.filter((s) => !correctIds.includes(s)).length;
      pts = Math.max(0, rightPicked - wrongPicked);
    }
    obtained += pts;
    maxTotal += max;

    let status;
    if (sel.length === 0) { status = "oubliee"; oubliees++; }
    else {
      const selSet = new Set(sel);
      const corSet = new Set(correctIds);
      const exact = selSet.size === corSet.size && [...selSet].every((s) => corSet.has(s));
      if (exact) { status = "bonne"; bonnes++; } else { status = "mauvaise"; mauvaises++; }
    }

    chapterStats[q.chapterId] = chapterStats[q.chapterId] || { correct: 0, total: 0 };
    chapterStats[q.chapterId].total += 1;
    if (status === "bonne") chapterStats[q.chapterId].correct += 1;

    return { ...q, selected: sel, correctIds, points: pts, max, status };
  });

  const percent = maxTotal ? (obtained / maxTotal) * 100 : 0;
  const note20 = maxTotal ? (obtained / maxTotal) * 20 : 0;

  return { obtained, maxTotal, percent, note20, bonnes, mauvaises, oubliees, chapterStats, details, totalItems: flat.length };
}

/* ---------------- Storage ---------------- */
const HISTORY_KEY = "infas-hemato:history";

async function loadHistory() {
  try {
    const res = await storage.get(HISTORY_KEY);
    return res ? JSON.parse(res.value) : [];
  } catch {
    return [];
  }
}
async function saveHistory(history) {
  try {
    await storage.set(HISTORY_KEY, JSON.stringify(history));
  } catch (e) {
    console.error("Erreur de sauvegarde", e);
  }
}

/* ---- Suivi des questions/cas déjà vus, pour éviter les répétitions d'une connexion à l'autre ---- */
const SEEN_KEY = "infas-hemato:seen";

async function loadSeen() {
  try {
    const res = await storage.get(SEEN_KEY);
    return res ? JSON.parse(res.value) : { q: [], c: [] };
  } catch {
    return { q: [], c: [] };
  }
}
async function saveSeen(seen) {
  try {
    await storage.set(SEEN_KEY, JSON.stringify(seen));
  } catch (e) {
    console.error("Erreur de sauvegarde (suivi des questions vues)", e);
  }
}

/* ---- Registre partagé des candidats (pour les statistiques administrateur) ---- */
const CANDIDATE_PREFIX = "infas-hemato:cand:";
function sanitizeKeyPart(s) {
  return (s || "").replace(/[^A-Za-z0-9+]/g, "");
}
function candidateKey(telephone) {
  return `${CANDIDATE_PREFIX}${sanitizeKeyPart(telephone)}`;
}

async function upsertCandidate(profile) {
  const key = candidateKey(profile.telephone);
  try {
    let existing = null;
    try {
      const r = await storage.get(key, true);
      existing = r ? JSON.parse(r.value) : null;
    } catch {
      existing = null;
    }
    const now = new Date().toISOString();
    const record = existing
      ? { ...existing, nom: profile.nom, prenom: profile.prenom, lastSeen: now }
      : { nom: profile.nom, prenom: profile.prenom, telephone: profile.telephone, firstSeen: now, lastSeen: now, examsCount: 0 };
    await storage.set(key, JSON.stringify(record), true);
    return record;
  } catch (e) {
    console.error("Erreur registre candidat", e);
    return null;
  }
}

async function incrementCandidateExamCount(telephone) {
  const key = candidateKey(telephone);
  try {
    const r = await storage.get(key, true);
    if (!r) return;
    const rec = JSON.parse(r.value);
    rec.examsCount = (rec.examsCount || 0) + 1;
    rec.lastSeen = new Date().toISOString();
    await storage.set(key, JSON.stringify(rec), true);
  } catch (e) {
    console.error("Erreur mise à jour candidat", e);
  }
}

async function loadAllCandidates() {
  try {
    const listRes = await storage.list(CANDIDATE_PREFIX, true);
    const keys = listRes?.keys || [];
    const records = [];
    for (const k of keys) {
      try {
        const r = await storage.get(k, true);
        if (r) records.push(JSON.parse(r.value));
      } catch {
        /* skip unreadable entry */
      }
    }
    return records;
  } catch (e) {
    console.error("Erreur chargement candidats", e);
    return [];
  }
}

