/* ---------------- Dashboard ---------------- */
function computeChapterMastery(history) {
  const agg = {};
  history.forEach((h) => {
    Object.entries(h.chapterStats || {}).forEach(([chId, s]) => {
      agg[chId] = agg[chId] || { correct: 0, total: 0 };
      agg[chId].correct += s.correct;
      agg[chId].total += s.total;
    });
  });
  return agg;
}

function Dashboard({ history, onStart, onTrain, onLogout, candidate }) {
  const validHistory = history.filter((h) => !h.aborted);
  const examCount = history.length;
  const avg = validHistory.length ? validHistory.reduce((a, h) => a + h.note20, 0) / validHistory.length : 0;
  const best = validHistory.length ? Math.max(...validHistory.map((h) => h.note20)) : 0;
  const mastery = computeChapterMastery(history);
  const mastered = CHAPTERS.filter((c) => mastery[c.id] && mastery[c.id].total >= 2 && mastery[c.id].correct / mastery[c.id].total >= 0.7);
  const toReview = CHAPTERS.filter((c) => mastery[c.id] && mastery[c.id].total >= 2 && mastery[c.id].correct / mastery[c.id].total < 0.5);

  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, fontFamily: "'IBM Plex Sans', sans-serif" }}>
      <TopBar onLogout={onLogout} />
      <div style={{ maxWidth: 920, margin: "0 auto", padding: "26px 18px 60px" }}>
        <div style={{ marginBottom: 18 }}>
          <h1 style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 22, color: COLORS.ink, margin: 0 }}>Tableau de bord</h1>
          <p style={{ color: COLORS.inkSoft, fontSize: 13, margin: "4px 0 0" }}>Bienvenue, {candidate?.prenom || "étudiant(e)"}. Voici votre progression sur le cours d'hématologie INFAS.</p>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))", gap: 12, marginBottom: 22 }}>
          <StatCard label="Examens réalisés" value={examCount} />
          <StatCard label="Moyenne" value={examCount ? `${avg.toFixed(1)}/20` : "—"} />
          <StatCard label="Meilleur score" value={examCount ? `${best.toFixed(1)}/20` : "—"} tone="green" />
          <StatCard label="Chapitres maîtrisés" value={mastered.length} tone="green" />
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 14, marginBottom: 26 }}>
          <div style={{ background: COLORS.green, borderRadius: 16, padding: "20px 20px", color: "white" }}>
            <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 16, marginBottom: 4 }}>📖 Entraînement</div>
            <div style={{ fontSize: 12.5, opacity: 0.9, marginBottom: 14 }}>Révisez par chapitre, sans limite de temps : la correction et l'explication s'affichent immédiatement après chaque réponse.</div>
            <button onClick={onTrain} style={{ ...primaryBtn, background: "white", color: COLORS.green, width: "100%" }}>
              Commencer une séance →
            </button>
          </div>
          <div style={{ background: COLORS.blueDeep, borderRadius: 16, padding: "20px 20px", color: "white" }}>
            <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 16, marginBottom: 4 }}>📝 Examen blanc</div>
            <div style={{ fontSize: 12.5, opacity: 0.9, marginBottom: 14 }}>Choisissez une matière et un niveau. Aucune correction affichée avant la fin de l'épreuve, comme au concours.</div>
            <button onClick={onStart} style={{ ...primaryBtn, background: COLORS.green, width: "100%" }}>
              Choisir une matière →
            </button>
          </div>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 26 }}>
          <ChapterList title="Chapitres maîtrisés" tone="green" chapters={mastered} empty="Pas encore de chapitre maîtrisé — continuez à vous entraîner." />
          <ChapterList title="Chapitres à retravailler" tone="red" chapters={toReview} empty="Aucun point faible identifié pour l'instant." />
        </div>

        <div>
          <h2 style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 15, color: COLORS.ink, marginBottom: 10 }}>Historique</h2>
          {history.length === 0 ? (
            <div style={{ color: COLORS.inkSoft, fontSize: 13, background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 12, padding: 18 }}>
              Aucun examen réalisé pour l'instant.
            </div>
          ) : (
            <div style={{ background: COLORS.surface, border: `1px solid ${COLORS.line}`, borderRadius: 12, overflow: "hidden" }}>
              {[...history].reverse().map((h, i) => (
                <div
                  key={h.id}
                  style={{
                    display: "flex", justifyContent: "space-between", alignItems: "center",
                    padding: "12px 16px", borderTop: i === 0 ? "none" : `1px solid ${COLORS.line}`, fontSize: 13,
                  }}
                >
                  <div>
                    <div style={{ fontWeight: 600, color: COLORS.ink, display: "flex", alignItems: "center", gap: 6 }}>
                      {SUBJ[h.subjectId] ? `${SUBJ[h.subjectId]} · ` : ""}{LEVELS.find((l) => l.id === h.levelId)?.label || h.levelId}
                      {h.aborted && <Badge tone="red">Interrompu</Badge>}
                    </div>
                    <div style={{ color: COLORS.inkSoft, fontSize: 11.5 }}>{fmtDate(h.date)} · {fmtTime(h.durationSec)}</div>
                  </div>
                  <div style={{ fontFamily: "'IBM Plex Mono', monospace", fontWeight: 600, color: h.aborted ? COLORS.inkSoft : h.note20 >= 10 ? COLORS.green : COLORS.red }}>
                    {h.aborted ? "—" : `${h.note20.toFixed(1)}/20`}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

